        try {
            // Create a new GroovyShell instance for script execution
            GroovyShell shell = new GroovyShell();

            // Parse the script content into a Script object
            Script script = shell.parse(scriptContent);

            // Execute the script and return the result
            return script.run();
        } catch (IllegalArgumentException e) {
            // Re-throw validation exceptions
            throw e;
        } catch (Exception e) {
            // Wrap any other exceptions in a custom runtime exception
            throw new ScriptExecutionException("Failed to execute script: " + e.getMessage(), e);
        }
    }

    /**
     * Custom exception for script execution failures.
     */
    public static class ScriptExecutionException extends RuntimeException {

        public ScriptExecutionException(String message, Throwable cause) {
            super(message, cause);
        }
    }
}
